def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0.0
        for j in range(1, 15):
            factor = (1 / (j**2)) * (ratio**j)
            if j % 3 == 0:
                factor *= 1.2
            elif j % 2 == 0:
                factor *= 1.05
            else:
                factor *= 0.8
            score += factor
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 2.5
        elif remaining < 0.1 * capacity:
            score *= 1.5
        elif remaining < 0.25 * capacity:
            score *= 1.1
        else:
            score *= 0.9
        mod3 = int(capacity) % 3 == 0
        mod5 = int(capacity) % 5 == 0
        mod7 = int(capacity) % 7 == 0
        if mod3 and mod5:
            score -= 0.1 * (capacity / 15)
        elif mod3 and mod7:
            score -= 0.08 * (capacity / 12)
        elif mod5 and mod7:
            score -= 0.07 * (capacity / 10)
        elif mod3:
            score -= 0.05 * (capacity / 10)
        elif mod5:
            score -= 0.1 * (capacity / 20)
        elif mod7:
            score -= 0.12 * (capacity / 25)
        else:
            score -= 0.03 * (capacity / 35)
        penalty = 0.0
        for k in range(1, 6):
            diff = abs(capacity - item * k)
            threshold = 0.015 * capacity / k
            if diff < threshold:
                penalty += 0.25 * k / (diff + 1e-8)
        score += penalty
        adjustment = 0
        for m in range(1, 5):
            if int(capacity) % m == 0:
                adjustment += 0.02 * m * ratio
            else:
                adjustment -= 0.01 * m
        score += adjustment
        if score < 0:
            score = 0.0
        priorities[i] = score
    return priorities
